// eval_harness.js — THE IMMUTABLE EVAL
//
// DO NOT EDIT THIS FILE during architecture search.
// It loads the pinned eval set, runs search_arch.js, and computes metrics.
//
// Usage: node research/eval_harness.js [--tag <name>] [--verbose]

const fs = require('node:fs');
const path = require('node:path');

const repoRoot = path.resolve(__dirname, '..');
const dataRoot = path.join(repoRoot, 'data', 'videos');

// Auto-load .env so the agent doesn't need to configure anything
require(path.join(repoRoot, 'src', 'lib', 'env.js')).loadEnvFile(repoRoot);

// ============================================================
// PINNED CONSTANTS — do not change
// ============================================================

const TOP_K = 5;
const IOU_THRESHOLDS = [0.3, 0.5];

// Composite score design:
// - 30% R@1 IoU>=0.5 (primary retrieval quality)
// - 20% MRR (ranking quality)
// - 10% R@1 IoU>=0.3 (loose retrieval — catches near-misses)
// - 15% simplicity (fewer lines in search_arch.js = better)
// - 15% cost efficiency (fewer embedding API calls per video = better)
// - 10% compute speed (less wall-clock time per eval = better)
//
// Hard fails: if ANY of these trigger, composite is capped at 0.10
// - R@1 IoU>=0.5 drops below 0.05 (search is basically broken)
// - More than 80% of queries return zero results
// - search_arch.js exceeds 500 lines (over-engineering)
// - Cost per video exceeds $0.05 (too expensive for production)
const COMPOSITE_WEIGHTS = {
  r1_iou50: 0.30,
  mrr: 0.20,
  r1_iou30: 0.10,
  simplicity: 0.15,
  cost: 0.15,
  speed: 0.10,
};
const HARD_FAIL_CAP = 0.10;
const MAX_LINES = 500;
const SIMPLICITY_BASELINE_LINES = 100;
const COST_BASELINE = 0.002;  // $0.002/video = score 1.0 (current sparse)
const COST_MAX = 0.05;        // $0.05/video = score 0.0, hard fail
const SPEED_BASELINE_MS = 5000;  // 5s per video = score 1.0
const SPEED_MAX_MS = 60000;      // 60s per video = score 0.0

// ============================================================
// LOAD EVAL SET
// ============================================================

function loadEvalSet() {
  const dirs = fs.readdirSync(dataRoot, { withFileTypes: true })
    .filter(d => d.isDirectory())
    .map(d => d.name);

  const videos = [];
  for (const id of dirs) {
    const evalPath = path.join(dataRoot, id, 'eval-queries.json');
    if (!fs.existsSync(evalPath)) continue;

    const manifestPath = path.join(dataRoot, id, 'manifest.json');
    const ocrPath = path.join(dataRoot, id, 'ocr.json');
    const transcriptPath = path.join(dataRoot, id, 'transcript.json');

    if (!fs.existsSync(manifestPath)) continue;

    videos.push({
      id,
      manifest: JSON.parse(fs.readFileSync(manifestPath, 'utf8')),
      ocr: fs.existsSync(ocrPath) ? JSON.parse(fs.readFileSync(ocrPath, 'utf8')) : null,
      transcript: fs.existsSync(transcriptPath) ? JSON.parse(fs.readFileSync(transcriptPath, 'utf8')) : null,
      evalQueries: JSON.parse(fs.readFileSync(evalPath, 'utf8')).queries,
    });
  }

  return videos;
}

// ============================================================
// IoU + METRICS — pinned implementations
// ============================================================

function computeBestIoU(matches, groundTruthSpans) {
  let best = { iou: 0, matchIdx: -1, spanIdx: -1 };
  for (let mi = 0; mi < matches.length; mi += 1) {
    const m = matches[mi];
    const mStart = m.startSec ?? m.atSec ?? 0;
    const mEnd = m.endSec ?? (mStart + 5);
    for (let si = 0; si < groundTruthSpans.length; si += 1) {
      const gt = groundTruthSpans[si];
      const inter = Math.max(0, Math.min(mEnd, gt.endSec) - Math.max(mStart, gt.startSec));
      const union = (mEnd - mStart) + (gt.endSec - gt.startSec) - inter;
      const iou = union > 0 ? inter / union : 0;
      if (iou > best.iou) best = { iou: Number(iou.toFixed(4)), matchIdx: mi, spanIdx: si };
    }
  }
  return best;
}

function computeReciprocalRank(matches, groundTruthSpans, iouThreshold) {
  for (let i = 0; i < matches.length; i += 1) {
    const m = matches[i];
    const mStart = m.startSec ?? m.atSec ?? 0;
    const mEnd = m.endSec ?? (mStart + 5);
    for (const gt of groundTruthSpans) {
      const inter = Math.max(0, Math.min(mEnd, gt.endSec) - Math.max(mStart, gt.startSec));
      const union = (mEnd - mStart) + (gt.endSec - gt.startSec) - inter;
      const iou = union > 0 ? inter / union : 0;
      if (iou >= iouThreshold) return 1 / (i + 1);
    }
  }
  return 0;
}

function computeComposite({ r1_iou50, r1_iou30, mrr, archLineCount, zeroResultFraction, costPerVideo, avgEvalMs }) {
  // Simplicity: 1.0 at baseline lines, linear decay to 0.0 at MAX_LINES
  const simplicity = Math.max(0, Math.min(1,
    1 - (archLineCount - SIMPLICITY_BASELINE_LINES) / (MAX_LINES - SIMPLICITY_BASELINE_LINES)
  ));

  // Cost efficiency: 1.0 at baseline cost, linear decay to 0.0 at max cost
  const costScore = Math.max(0, Math.min(1,
    1 - (costPerVideo - COST_BASELINE) / (COST_MAX - COST_BASELINE)
  ));

  // Speed: 1.0 at baseline speed, linear decay to 0.0 at max time
  const speedScore = Math.max(0, Math.min(1,
    1 - (avgEvalMs - SPEED_BASELINE_MS) / (SPEED_MAX_MS - SPEED_BASELINE_MS)
  ));

  let score = (
    COMPOSITE_WEIGHTS.r1_iou50 * r1_iou50 +
    COMPOSITE_WEIGHTS.mrr * mrr +
    COMPOSITE_WEIGHTS.r1_iou30 * r1_iou30 +
    COMPOSITE_WEIGHTS.simplicity * simplicity +
    COMPOSITE_WEIGHTS.cost * costScore +
    COMPOSITE_WEIGHTS.speed * speedScore
  );

  // Hard fails: cap score
  const hardFails = [];
  if (r1_iou50 < 0.05) hardFails.push(`R@1_IoU>=0.5 below 0.05 (${r1_iou50})`);
  if (zeroResultFraction > 0.80) hardFails.push(`${(zeroResultFraction * 100).toFixed(0)}% queries returned zero results`);
  if (archLineCount > MAX_LINES) hardFails.push(`search_arch.js has ${archLineCount} lines (max ${MAX_LINES})`);
  if (costPerVideo > COST_MAX) hardFails.push(`cost $${costPerVideo.toFixed(4)}/video exceeds $${COST_MAX}`);

  if (hardFails.length > 0) {
    score = Math.min(score, HARD_FAIL_CAP);
  }

  return {
    score: Number(score.toFixed(6)),
    simplicity: Number(simplicity.toFixed(4)),
    costScore: Number(costScore.toFixed(4)),
    speedScore: Number(speedScore.toFixed(4)),
    costPerVideo: Number(costPerVideo.toFixed(6)),
    avgEvalMs: Math.round(avgEvalMs),
    archLineCount,
    hardFails,
  };
}

// ============================================================
// MOCK EMBEDDING FUNCTIONS (for cost-free re-ranking experiments)
// ============================================================

function mockVector(seed, dimensions) {
  const crypto = require('node:crypto');
  const hash = crypto.createHash('sha256').update(String(seed)).digest();
  const vector = new Array(dimensions);
  for (let i = 0; i < dimensions; i += 1) {
    const b1 = hash[(i * 2) % hash.length];
    const b2 = hash[(i * 2 + 1) % hash.length];
    vector[i] = ((b1 * 256 + b2) / 65535) * 2 - 1;
  }
  let mag = 0;
  for (let i = 0; i < dimensions; i += 1) mag += vector[i] * vector[i];
  mag = Math.sqrt(mag);
  if (mag > 0) for (let i = 0; i < dimensions; i += 1) vector[i] = Number((vector[i] / mag).toFixed(6));
  return vector;
}

// ============================================================
// MAIN EVAL LOOP
// ============================================================

async function runEval(options = {}) {
  const { verbose, tag } = options;

  const { KNOBS, buildSearchEmbeddings, rankAndMerge } = require('./search_arch.js');
  const { findMatches } = require(path.join(repoRoot, 'src', 'lib', 'search.js'));

  const evalSet = loadEvalSet();
  if (evalSet.length === 0) {
    console.error('No eval data found. Run the dense eval pipeline first.');
    process.exit(1);
  }

  // Check if we have REAL embeddings (from actual API calls) cached
  const useRealEmbeddings = evalSet.every(v => {
    const embPath = path.join(dataRoot, v.id, 'embeddings.json');
    return fs.existsSync(embPath);
  }) && !!process.env.GEMINI_API_KEY;

  // Provide embed functions: real if API key available, mock otherwise
  const embedModule = require(path.join(repoRoot, 'src', 'lib', 'embed.js'));
  const embedText = useRealEmbeddings
    ? embedModule.embedText
    : async ({ text, dimensions }) => mockVector(text, dimensions || KNOBS.dimensions);
  const embedImage = useRealEmbeddings
    ? embedModule.embedImage
    : async ({ imagePath, dimensions }) => mockVector(imagePath, dimensions || KNOBS.dimensions);

  const videoResults = [];
  const evalStartMs = Date.now();

  for (const video of evalSet) {
    const videoStartMs = Date.now();
    let embeddingItems;

    if (useRealEmbeddings) {
      const embData = JSON.parse(fs.readFileSync(path.join(dataRoot, video.id, 'embeddings.json'), 'utf8'));
      embeddingItems = embData.items;
    } else {
      embeddingItems = await buildSearchEmbeddings({
        embedText, embedImage, apiKey: null,
        manifest: video.manifest, ocr: video.ocr, transcript: video.transcript,
      });
    }

    const queryResults = [];

    // Reset lib.js cost tracker per video if it's loaded
    try { require('./lib.js').resetCostTracker(); } catch {}

    for (const eq of video.evalQueries) {
      // Reset per-query budget
      try { require('./lib.js').resetQueryCallCount(); } catch {}

      // Embed query (uses real or mock depending on useRealEmbeddings)
      const queryVec = await embedText({
        apiKey: process.env.GEMINI_API_KEY || null,
        text: eq.query,
        model: 'gemini-embedding-2-preview',
        taskType: 'RETRIEVAL_QUERY',
        dimensions: KNOBS.dimensions,
      });

      const lexicalMatches = findMatches({
        query: eq.query,
        ocr: video.ocr,
        transcript: video.transcript,
      });

      const matches = rankAndMerge({
        queryVec,
        embeddings: embeddingItems,
        lexicalMatches,
        topK: TOP_K,
      });

      const bestIoU = computeBestIoU(matches, eq.groundTruthSpans);
      const rr = computeReciprocalRank(matches, eq.groundTruthSpans, 0.3);

      queryResults.push({
        query: eq.query,
        modality: eq.modality,
        difficulty: eq.difficulty,
        bestIoU: bestIoU.iou,
        r1_iou50: bestIoU.iou >= 0.5,
        r1_iou30: bestIoU.iou >= 0.3,
        reciprocalRank: Number(rr.toFixed(4)),
      });
    }

    const n = queryResults.length;
    const r1_50 = queryResults.filter(r => r.r1_iou50).length / Math.max(1, n);
    const r1_30 = queryResults.filter(r => r.r1_iou30).length / Math.max(1, n);
    const mrr = queryResults.reduce((s, r) => s + r.reciprocalRank, 0) / Math.max(1, n);
    const mIoU = queryResults.reduce((s, r) => s + r.bestIoU, 0) / Math.max(1, n);

    const videoElapsedMs = Date.now() - videoStartMs;

    videoResults.push({
      id: video.id,
      queries: n,
      r1_iou50: Number(r1_50.toFixed(4)),
      r1_iou30: Number(r1_30.toFixed(4)),
      mrr: Number(mrr.toFixed(4)),
      meanIoU: Number(mIoU.toFixed(4)),
      elapsedMs: videoElapsedMs,
      embeddingCount: embeddingItems.length,
      details: verbose ? queryResults : undefined,
    });
  }

  const totalElapsedMs = Date.now() - evalStartMs;

  // Aggregate
  const totalQueries = videoResults.reduce((s, v) => s + v.queries, 0);
  const avgR1_50 = Number((videoResults.reduce((s, v) => s + v.r1_iou50, 0) / videoResults.length).toFixed(4));
  const avgR1_30 = Number((videoResults.reduce((s, v) => s + v.r1_iou30, 0) / videoResults.length).toFixed(4));
  const avgMRR = Number((videoResults.reduce((s, v) => s + v.mrr, 0) / videoResults.length).toFixed(4));
  const avgMIoU = Number((videoResults.reduce((s, v) => s + v.meanIoU, 0) / videoResults.length).toFixed(4));
  const avgEvalMs = totalElapsedMs / videoResults.length;
  const zeroResultCount = videoResults.reduce((s, v) =>
    s + (v.details || []).filter(d => d.bestIoU === 0).length, 0);
  const zeroResultFraction = totalQueries > 0 ? zeroResultCount / totalQueries : 0;

  // Cost estimate: embedding cost + any API calls from lib.js
  const avgEmbeddingsPerVideo = videoResults.reduce((s, v) => s + v.embeddingCount, 0) / videoResults.length;
  const embedCostPerItem = 0.000002;
  const imageCostPerItem = 0.00012;
  let apiCostPerVideo = 0;
  try { apiCostPerVideo = require('./lib.js').getCostStats().totalCostUsd / videoResults.length; } catch {}
  const costPerVideo = avgEmbeddingsPerVideo * embedCostPerItem
    + (KNOBS.framesEnabled ? 8 * imageCostPerItem : 0)
    + apiCostPerVideo;

  // Measure code complexity
  const archPath = path.join(__dirname, 'search_arch.js');
  const archLines = fs.readFileSync(archPath, 'utf8').split('\n').length;

  const composite = computeComposite({
    r1_iou50: avgR1_50, r1_iou30: avgR1_30, mrr: avgMRR,
    archLineCount: archLines, zeroResultFraction,
    costPerVideo, avgEvalMs,
  });

  const result = {
    tag: tag || null,
    createdAt: new Date().toISOString(),
    knobs: KNOBS,
    useRealEmbeddings,
    totalVideos: videoResults.length,
    totalQueries,
    summary: {
      'R@1_IoU>=0.5': avgR1_50,
      'R@1_IoU>=0.3': avgR1_30,
      MRR: avgMRR,
      meanIoU: avgMIoU,
      composite: composite.score,
      simplicity: composite.simplicity,
      costScore: composite.costScore,
      speedScore: composite.speedScore,
      costPerVideo: composite.costPerVideo,
      avgEvalMs: composite.avgEvalMs,
      archLines: composite.archLineCount,
      hardFails: composite.hardFails,
    },
    videos: videoResults,
  };

  return result;
}

// ============================================================
// CLI ENTRY POINT
// ============================================================

if (require.main === module) {
  const args = process.argv.slice(2);
  const tag = args.includes('--tag') ? args[args.indexOf('--tag') + 1] : null;
  const verbose = args.includes('--verbose');

  runEval({ tag, verbose }).then(result => {
    // Print summary table
    console.log(`\n=== ${result.tag || 'EVAL'} (${result.useRealEmbeddings ? 'REAL' : 'MOCK'} embeddings) ===\n`);
    console.log('Video                              | Queries | R@1≥.5 | R@1≥.3 | MRR    | mIoU');
    console.log('-----------------------------------|---------|--------|--------|--------|------');
    for (const v of result.videos) {
      const name = v.id.slice(0, 35).padEnd(35);
      console.log(`${name}| ${String(v.queries).padEnd(8)}| ${String(v.r1_iou50).padEnd(7)}| ${String(v.r1_iou30).padEnd(7)}| ${String(v.mrr).padEnd(7)}| ${v.meanIoU}`);
    }
    console.log('-----------------------------------|---------|--------|--------|--------|------');
    const s = result.summary;
    console.log(`${'AVERAGE'.padEnd(35)}| ${String(result.totalQueries).padEnd(8)}| ${String(s['R@1_IoU>=0.5']).padEnd(7)}| ${String(s['R@1_IoU>=0.3']).padEnd(7)}| ${String(s.MRR).padEnd(7)}| ${s.meanIoU}`);
    console.log(`\nCOMPOSITE SCORE: ${s.composite}`);
    console.log(`  retrieval: R@1≥.5=${s['R@1_IoU>=0.5']} R@1≥.3=${s['R@1_IoU>=0.3']} MRR=${s.MRR}`);
    console.log(`  efficiency: simplicity=${s.simplicity} (${s.archLines} lines) cost=${s.costScore} ($${s.costPerVideo}/vid) speed=${s.speedScore} (${s.avgEvalMs}ms/vid)`);
    if (s.hardFails && s.hardFails.length > 0) {
      console.log(`  HARD FAILS: ${s.hardFails.join('; ')}`);
    }
    console.log(`KNOBS: ${JSON.stringify(result.knobs)}`);

    // Append to results.tsv
    const tsvPath = path.join(__dirname, 'results.tsv');
    const tsvExists = fs.existsSync(tsvPath);
    const tsvLine = [
      result.tag || 'unnamed',
      s.composite,
      s['R@1_IoU>=0.5'],
      s.MRR,
      s.simplicity,
      s.costScore,
      s.speedScore,
      s.archLines,
      '$' + s.costPerVideo,
      s.avgEvalMs + 'ms',
      s.hardFails.length > 0 ? 'FAIL:' + s.hardFails.join(';') : 'ok',
      result.useRealEmbeddings ? 'real' : 'mock',
    ].join('\t');

    if (!tsvExists) {
      fs.writeFileSync(tsvPath, 'tag\tcomposite\tR@1≥.5\tMRR\tsimplicity\tcost\tspeed\tlines\t$/vid\tms/vid\tstatus\tembeddings\n');
    }
    fs.appendFileSync(tsvPath, tsvLine + '\n');
    console.log(`\nAppended to ${tsvPath}`);
  }).catch(err => {
    console.error(err);
    process.exit(1);
  });
}

module.exports = { runEval, computeBestIoU, computeReciprocalRank };
